<template>
  <div class="AppNavbar">
    <v-app-bar app absolute color="transparent" flat>
      <router-link :to="{name: 'home'}" class="logo">Simone Carletti</router-link>

      <v-spacer></v-spacer>

      <a class="nav-icon" ref="navIcon" v-if="$vuetify.breakpoint.xsOnly" @click="openNavDrawer">
        <v-icon>mdi-menu</v-icon>
      </a>
      <template v-else>
        <router-link
          v-for="link in links"
          :key="link.routeName"
          :to="{name: link.routeName}"
          class="link"
        >{{link.text}}</router-link>
        <a
          v-for="link in socialLinks"
          :key="link.url"
          :href="link.url"
          target="_blank"
          class="link social"
        >
          <v-icon>{{link.icon}}</v-icon>
        </a>
      </template>
    </v-app-bar>

    <AppNavDrawer
      :open="isNavDrawerOpen"
      @close="closeNavDrawer"
      :links="links"
      :socials="socialLinks"
    ></AppNavDrawer>
  </div>
</template>

<script>
import AppNavDrawer from "@/components/AppNavDrawer.vue";

export default {
  name: "AppNavbar",
  components: { AppNavDrawer },
  data() {
    return {
      isNavDrawerOpen: false,
      links: [
        {
          routeName: "projects",
          text: "Projects"
        },
        {
          routeName: "photography",
          text: "Photography"
        },
        {
          routeName: "contact",
          text: "Contact"
        }
      ],
      socialLinks: [
        {
          url: "https://github.com/regi18",
          icon: "mdi-github"
        },
        {
          url: "https://www.instagram.com/simone_carletti/",
          icon: "mdi-instagram"
        }
      ]
    };
  },
  methods: {
    openNavDrawer() {
      this.$refs.navIcon.style.opacity = 0;

      this.isNavDrawerOpen = true;
    },
    closeNavDrawer() {
      this.isNavDrawerOpen = false;

      this.$refs.navIcon.style.opacity = 1;
    }
  }
};
</script>

<style scoped>
.logo {
  font-family: "ABold";
  font-size: 1.6em;
  line-height: 80%;
}

a {
  font-family: "AMedium";
}

a.nav-icon {
  transition: opacity 300ms;
}

.link {
  padding-right: 1em;
  padding-left: 1em;
}

.link.social {
  padding-right: 0.5em;
  padding-left: 0.5em;
}

/* why first-child doesn't work???? */
a[href*="github"] {
  padding-left: 1rem !important;
}

.link:hover,
.link:hover i {
  color: #6c6c6c;
  transition: color 300ms;
}
</style>