<template>
  <v-app>
    <AppNavbar />

    <v-main class="mb-10 mb-sm-0">
      <v-container fluid class="fill-height">
        <router-view></router-view>
      </v-container>
    </v-main>

    <!-- how footer only if user has scrolled once to the bottom
    In this way if a user just scroll to the bottom 
    the About section will remain neat without the footer-->
    <AppFooter v-if="scrolledToBottomOnce || $vuetify.breakpoint.xsOnly || $route.name !== 'home'" />
  </v-app>
</template>

<script>
/* eslint-disable */
import AppNavbar from "@/components/AppNavbar";
import AppFooter from "@/components/AppFooter.vue";

export default {
  name: "App",
  components: {
    AppNavbar,
    AppFooter
  },
  data() {
    return {
      scrolledToBottomOnce: false
    };
  },
  methods: {
    // Checks if user scrolled to the bottom of the page
    scroll() {
      window.onscroll = () => {
        let bottomOfWindow =
          Math.max(
            window.pageYOffset,
            document.documentElement.scrollTop,
            document.body.scrollTop
          ) +
            window.innerHeight ===
          document.documentElement.offsetHeight;

        if (bottomOfWindow) {
          this.scrolledToBottomOnce = true;
        }
      };
    },
    setVhCssVariable() {
      let getVh = () => {
        let vh = window.innerHeight * 0.01;
        document.documentElement.style.setProperty("--vh", `${vh}px`);
      };

      getVh();
      window.addEventListener("resize", getVh());
    }
  },
  created() {
    this.setVhCssVariable();
  },
  mounted() {
    this.scroll();
  }
};
</script>

